module RefModule(
	input clk,
	input  [7:0] p0,p1,p2,p3,p4,p5,p6,p7,p8,		
	output reg [7:0] median_out
    );reg [7:0] unused_val [8:0];

	reg [7:0] temp[7:0];

	integer j;
	integer i;

	always @(posedge clk)
	begin
		unused_val[0] = p0;
		unused_val[1] = p1;
		unused_val[2] = p2;
		unused_val[3] = p3;
		unused_val[4] = p4;
		unused_val[5] = p5;
		unused_val[6] = p6;
		unused_val[7] = p7;
		unused_val[8] = p8;

		 for (i = 0; i < 9; i = i+1)        
			for (j = 0; j < 8-i; j = j+1)  
			  if (unused_val[j] > unused_val[j+1]) begin 
					temp[j] = unused_val[j];
					unused_val[j] = unused_val[j+1];
					unused_val[j+1] = temp[j];
					end

		median_out = unused_val[4];
	end

endmodule
